const express = require('express');
const app = express();
app.use(express.json());

const users = [
  { id: 1, name: 'Alice' },
  { id: 2, name: 'Bob' }
];

app.get('/users', (req, res) => {
  res.json(users);
});

app.get('/users/:id', (req, res) => {
  const user = users.find(u => u.id === parseInt(req.params.id));
  if (user) res.json(user);
  else res.status(404).send('User not found');
});

const PORT = 3000;
app.listen(PORT, () => {
  console.log(`User Service running on port ${PORT}`);
});

const express = require('express');
const app = express();
app.use(express.json());

const orders = [
  { id: 1, userId: 1, product: 'Book' },
  { id: 2, userId: 2, product: 'Pen' }
];

app.get('/orders', (req, res) => {
  res.json(orders);
});

app.get('/orders/:id', (req, res) => {
  const order = orders.find(o => o.id === parseInt(req.params.id));
  if (order) res.json(order);
  else res.status(404).send('Order not found');
});

const PORT = 3001;
app.listen(PORT, () => {
  console.log(`Order Service running on port ${PORT}`);
});

const fetch = require('node-fetch');

app.get('/orders-with-user/:id', async (req, res) => {
  const order = orders.find(o => o.id === parseInt(req.params.id));
  if (!order) return res.status(404).send('Order not found');

  try {
    const userResponse = await fetch(`http://localhost:3000/users/${order.userId}`);
    if (!userResponse.ok) return res.status(502).send('Failed to fetch user');
    const user = await userResponse.json();

    res.json({ ...order, user });
  } catch (error) {
    res.status(500).send('Internal Server Error');
  }
});

function blockEventLoop() {
  const start = Date.now();
  while (Date.now() - start < 3000) {
    // Blocking loop for 3 seconds
  }
  console.log('Finished blocking operation');
}

blockEventLoop();
console.log('This runs after the blocking function.');

function nonBlockingTask() {
  let count = 0;
  function doChunk() {
    for (let i = 0; i < 1000; i++) {
      count++;
    }
    console.log('Processed chunk, count:', count);
    if (count < 100000) {
      setTimeout(doChunk, 0); // Yield control so UI stays responsive
    }
  }
  doChunk();
}

nonBlockingTask();

